export enum ProjectStatus {
  CREATED = '已创建',
  IN_PROGRESS = '标书制作中',
  CHECKING = '检查中',
  SUBMITTED = '已提交',
  OPENED = '已开标',
  WON = '已中标',
  LOST = '未中标'
}

export enum EventType {
  DEADLINE = 'DEADLINE',
  OPENING = 'OPENING',
  REMINDER = 'REMINDER'
}

export interface CalendarEvent {
  id: string;
