// Helper to get dates relative to today
const getRelativeDate = (days: number, hours: number = 9, minutes: number = 0) => {
  const d = new Date();
  d.setDate(d.getDate() + days);
  d.setHours(hours, minutes, 0, 0);
  return d;
};

