import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  children: React.ReactNode;
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  variant = 'primary', 
  size = 'md', 
  children, 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded transition-all duration-300 font-medium focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-brand-dark/50";

  const variants = {
    primary: "bg-gradient-to-br from-[#125FFA] to-[#0A47C7] text-white hover:shadow-lg hover:-translate-y-0.5 border border-transparent",
    secondary: "bg-white text-text-primary border border-[#D9DCDF] hover:border-brand hover:text-brand hover:bg-brand-light/10",
    outline: "bg-transparent border border-[#125FFA] text-[#125FFA] hover:bg-[#125FFA]/5",
    ghost: "bg-transparent text-text-secondary hover:bg-gray-100 hover:text-text-primary",
  };

  const sizes = {
    sm: "h-8 px-3 text-xs",
    md: "h-9 px-6 text-sm", // Requested 36px height
    lg: "h-12 px-8 text-base",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

