export const TenderCalendar: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [view, setView] = useState<'month' | 'week'>('month');
  const [modalOpen, setModalOpen] = useState(false);

  // Normalize date to remove time for comparison
  const normalizeDate = (d: Date) => new Date(d.getFullYear(), d.getMonth(), d.getDate());

  // Generate days for grid
  const getCalendarDays = () => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const days: { date: Date; isCurrentMonth: boolean }[] = [];

    if (view === 'month') {
      const firstDayOfMonth = new Date(year, month, 1);
      const startingDayOfWeek = firstDayOfMonth.getDay() === 0 ? 6 : firstDayOfMonth.getDay() - 1; // Start Mon

      // Previous month days
      const prevMonth = new Date(year, month, 0);
      for (let i = startingDayOfWeek - 1; i >= 0; i--) {
        days.push({ 
          date: new Date(year, month - 1, prevMonth.getDate() - i), 
          isCurrentMonth: false 
        });
      }

      // Current month days
      const lastDayOfMonth = new Date(year, month + 1, 0).getDate();
      for (let i = 1; i <= lastDayOfMonth; i++) {
        days.push({ date: new Date(year, month, i), isCurrentMonth: true });
      }

      // Next month days to fill 42 cells (6 rows)
      const remaining = 42 - days.length;
      for (let i = 1; i <= remaining; i++) {
        days.push({ date: new Date(year, month + 1, i), isCurrentMonth: false });
      }
    } else {
      // Week View
      const currentDay = currentDate.getDay() === 0 ? 6 : currentDate.getDay() - 1; // 0=Mon
      const startOfWeek = new Date(currentDate);
      startOfWeek.setDate(currentDate.getDate() - currentDay);

      for(let i=0; i<7; i++) {
        const d = new Date(startOfWeek);
        d.setDate(startOfWeek.getDate() + i);
        days.push({ date: d, isCurrentMonth: d.getMonth() === month });
      }
    }

    return days;
  };

  const getEventsForDate = (date: Date) => {
    const norm = normalizeDate(date).getTime();
    return MOCK_EVENTS.filter(e => normalizeDate(e.date).getTime() === norm && !e.completed);
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    const events = getEventsForDate(date);
    if (events.length > 0) {
      setModalOpen(true);
    }
  };

  const navigate = (dir: 'prev' | 'next') => {
    const newDate = new Date(currentDate);
    if (view === 'month') {
      newDate.setMonth(newDate.getMonth() + (dir === 'next' ? 1 : -1));
    } else {
      newDate.setDate(newDate.getDate() + (dir === 'next' ? 7 : -7));
    }
    setCurrentDate(newDate);
  };

  const today = new Date();
  const selectedEvents = getEventsForDate(selectedDate);

  // Todo List Data (Today + 3 days)
  const todoList = MOCK_EVENTS.filter(e => {
    const diff = normalizeDate(e.date).getTime() - normalizeDate(today).getTime();
    const dayDiff = diff / (1000 * 3600 * 24);
    return dayDiff >= 0 && dayDiff <= 3 && !e.completed;
  }).sort((a, b) => a.date.getTime() - b.date.getTime());

  return (
    <div className="bg-white rounded-lg shadow-sm border border-[#D9DCDF] overflow-hidden flex flex-col h-full">
      {/* Header */}
      <div className="p-4 border-b border-gray-100 flex items-center justify-between">
        <div className="flex items-center gap-2">
           <CalendarIcon size={18} className="text-brand" />
           <span className="font-bold text-text-primary">投标日历</span>
        </div>
        <div className="flex gap-2 text-xs">
          <div className="flex border border-[#D9DCDF] rounded overflow-hidden">
            <button 
              onClick={() => setView('month')}
              className={`px-2 py-1 ${view === 'month' ? 'bg-brand text-white' : 'bg-white hover:bg-gray-50'}`}
            >
              月
            </button>
            <div className="w-px bg-[#D9DCDF]" />
            <button 
              onClick={() => setView('week')}
              className={`px-2 py-1 ${view === 'week' ? 'bg-brand text-white' : 'bg-white hover:bg-gray-50'}`}
            >
              周
            </button>
          </div>
          <button 
             onClick={() => { setCurrentDate(new Date()); setSelectedDate(new Date()); }}
             className="px-2 py-1 border border-[#D9DCDF] rounded hover:bg-gray-50"
          >
            今
          </button>
        </div>
      </div>

      {/* Navigation & Month Label */}
      <div className="flex items-center justify-between px-4 py-2 bg-gray-50/50">
        <button onClick={() => navigate('prev')} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronLeft size={16}/></button>
        <span className="text-sm font-semibold text-text-primary">
          {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
        </span>
        <button onClick={() => navigate('next')} className="p-1 hover:bg-gray-200 rounded text-gray-500"><ChevronRight size={16}/></button>
      </div>

      {/* Calendar Grid */}
      <div className="p-2">
        {/* Week Headers */}
        <div className="grid grid-cols-7 mb-1">
          {['一', '二', '三', '四', '五', '六', '日'].map(d => (
            <div key={d} className="text-center text-xs text-text-tertiary py-1">{d}</div>
          ))}
        </div>

        {/* Days */}
        <div className="grid grid-cols-7 border-t border-l border-gray-50 bg-white">
          {getCalendarDays().map((item, idx) => (
            <CalendarDay 
              key={idx}
              date={item.date}
              isCurrentMonth={item.isCurrentMonth}
              isToday={normalizeDate(item.date).getTime() === normalizeDate(today).getTime()}
              isSelected={normalizeDate(item.date).getTime() === normalizeDate(selectedDate).getTime()}
              events={getEventsForDate(item.date)}
              onClick={handleDateClick}
              view={view}
            />
          ))}
        </div>
      </div>

      {/* Legend */}
      <div className="px-4 pb-2 flex gap-4 justify-center border-b border-gray-100">
        <div className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-functional-error" />
          <span className="text-[10px] text-text-tertiary">投标截止</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-brand" />
          <span className="text-[10px] text-text-tertiary">开标时间</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-functional-warning" />
          <span className="text-[10px] text-text-tertiary">提醒</span>
        </div>
      </div>

      {/* Todo List Area */}
      <div className="flex-1 bg-[#FAFBFC] p-4 overflow-y-auto max-h-60">
        <h4 className="text-xs font-bold text-text-secondary mb-3 uppercase tracking-wider">近期待办</h4>
        <div className="space-y-2">
          {todoList.length > 0 ? (
            todoList.map(event => (
              <div key={event.id} className="bg-white p-3 rounded border border-gray-200 shadow-sm flex items-start gap-3 hover:shadow-md transition-shadow cursor-pointer">
                <div className={`shrink-0 w-1 h-full rounded-full self-stretch ${
                  event.type === EventType.DEADLINE ? 'bg-functional-error' : 
                  event.type === EventType.OPENING ? 'bg-brand' : 'bg-functional-warning'
                }`} />
                <div className="flex-1 min-w-0">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-xs font-bold text-text-primary">
                      {event.date.getMonth()+1}/{event.date.getDate()} {event.timeStr}
                    </span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded ${
                      event.type === EventType.DEADLINE ? 'bg-red-50 text-red-600' : 'bg-blue-50 text-blue-600'
                    }`}>
                      {event.type === EventType.DEADLINE ? '截止' : event.type === EventType.OPENING ? '开标' : '提醒'}
                    </span>
                  </div>
                  <p className="text-xs text-text-secondary truncate" title={event.projectName}>{event.projectName}</p>
                </div>
              </div>
            ))
          ) : (
             <div className="text-center py-4 text-xs text-gray-400">
               近期无待办事项
             </div>
          )}
        </div>
      </div>

      {/* Modal Dialog */}
      {modalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-lg shadow-2xl w-full max-w-sm mx-4 overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h3 className="font-bold text-text-primary">
                {selectedDate.getMonth()+1}月{selectedDate.getDate()}日 待办事项
              </h3>
              <button onClick={() => setModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                <X size={20} />
              </button>
            </div>
            <div className="p-4 max-h-[300px] overflow-y-auto">
              {selectedEvents.map(event => (
                <div key={event.id} className="mb-4 last:mb-0 p-3 bg-gray-50 rounded-lg border border-gray-100">
                  <div className="flex items-start gap-2 mb-2">
                    <div className={`mt-1 w-2 h-2 rounded-full shrink-0 ${
                      event.type === EventType.DEADLINE ? 'bg-functional-error' : 
                      event.type === EventType.OPENING ? 'bg-brand' : 'bg-functional-warning'
                    }`} />
                    <h5 className="text-sm font-medium text-text-primary leading-tight">{event.projectName}</h5>
                  </div>
                  <div className="pl-4 flex justify-between items-center">
                    <span className="text-xs text-text-tertiary">时间: {event.timeStr}</span>
                    <button className="text-xs flex items-center gap-1 text-brand hover:text-brand-dark transition-colors">
                      <CheckSquare size={12} /> 标记完成
                    </button>
                  </div>
                </div>
              ))}
            </div>
            <div className="p-3 bg-gray-50 border-t border-gray-100 text-center">
              <button onClick={() => setModalOpen(false)} className="text-xs text-text-secondary hover:text-text-primary">
                关闭
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

