import React from 'react';
import { CalendarEvent, EventType } from '../../types';

interface CalendarDayProps {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  isSelected: boolean;
  events: CalendarEvent[];
  onClick: (date: Date) => void;
  view: 'month' | 'week';
}

export const CalendarDay: React.FC<CalendarDayProps> = ({
  date,
  isCurrentMonth,
  isToday,
  isSelected,
  events,
  onClick,
  view
}) => {
  // Sort events by priority: Deadline (Red) > Opening (Blue) > Reminder (Yellow)
  const sortedEvents = [...events].sort((a, b) => {
    const priority = { [EventType.DEADLINE]: 3, [EventType.OPENING]: 2, [EventType.REMINDER]: 1 };
    return priority[b.type] - priority[a.type];
  });

  const getEventColor = (type: EventType) => {
    switch (type) {
      case EventType.DEADLINE: return 'bg-functional-error';
      case EventType.OPENING: return 'bg-brand';
      case EventType.REMINDER: return 'bg-functional-warning';
      default: return 'bg-gray-400';
    }
  };

  const isMonthView = view === 'month';

  return (
    <button 
      onClick={() => onClick(date)}
      className={`
        flex flex-col items-center justify-start pt-2 pb-1 rounded-lg transition-all duration-200
        ${isMonthView ? 'aspect-square sm:aspect-auto sm:h-14' : 'h-20'}
        ${!isCurrentMonth ? 'opacity-30' : 'opacity-100'}
        ${isSelected 
          ? 'bg-brand/10 text-brand font-medium ring-1 ring-brand ring-inset' 
          : 'hover:bg-gray-50 text-text-primary'
        }
      `}
    >
      {/* Date Number */}
      <span 
        className={`
          text-xs w-7 h-7 flex items-center justify-center rounded-full mb-1.5 transition-all
          ${isToday 
            ? 'bg-brand text-white font-bold shadow-md shadow-brand/30 scale-110' 
            : ''}
        `}
      >
        {date.getDate()}
      </span>

      {/* Event Dots */}
      <div className="flex gap-1 h-1.5">
        {sortedEvents.slice(0, 3).map((e, i) => (
           <div key={`${e.id}-${i}`} className={`w-1.5 h-1.5 rounded-full ${getEventColor(e.type)}`} />
        ))}
      </div>
    </button>
  );
};

import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, X, CheckSquare, Calendar as CalendarIcon } from 'lucide-react';
import { CalendarDay } from './CalendarDay';
import { MOCK_EVENTS } from '../../constants';
import { EventType } from '../../types';

export const TenderCalendar: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [view, setView] = useState<'month' | 'week'>('week');
  const [modalOpen, setModalOpen] = useState(false);

  // Normalize date to remove time for comparison
  const normalizeDate = (d: Date) => new Date(d.getFullYear(), d.getMonth(), d.getDate());

  // Generate days for grid
  const getCalendarDays = () => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const days: { date: Date; isCurrentMonth: boolean }[] = [];

    if (view === 'month') {
      const firstDayOfMonth = new Date(year, month, 1);
      const startingDayOfWeek = firstDayOfMonth.getDay() === 0 ? 6 : firstDayOfMonth.getDay() - 1; // Start Mon

      // Previous month days
      const prevMonth = new Date(year, month, 0);
      for (let i = startingDayOfWeek - 1; i >= 0; i--) {
        days.push({ 
          date: new Date(year, month - 1, prevMonth.getDate() - i), 
          isCurrentMonth: false 
        });
      }

      // Current month days
      const lastDayOfMonth = new Date(year, month + 1, 0).getDate();
      for (let i = 1; i <= lastDayOfMonth; i++) {
        days.push({ date: new Date(year, month, i), isCurrentMonth: true });
      }

      // Next month days to fill 42 cells (6 rows)
      const remaining = 42 - days.length;
      for (let i = 1; i <= remaining; i++) {
        days.push({ date: new Date(year, month + 1, i), isCurrentMonth: false });
      }
    } else {
      // Week View
      const currentDay = currentDate.getDay() === 0 ? 6 : currentDate.getDay() - 1; // 0=Mon
      const startOfWeek = new Date(currentDate);
      startOfWeek.setDate(currentDate.getDate() - currentDay);

      for(let i=0; i<7; i++) {
        const d = new Date(startOfWeek);
        d.setDate(startOfWeek.getDate() + i);
        days.push({ date: d, isCurrentMonth: d.getMonth() === month });
      }
    }

    return days;
  };

  const getEventsForDate = (date: Date) => {
    const norm = normalizeDate(date).getTime();
    return MOCK_EVENTS.filter(e => normalizeDate(e.date).getTime() === norm && !e.completed);
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    const events = getEventsForDate(date);
    if (events.length > 0) {
      setModalOpen(true);
    }
  };

  const navigate = (dir: 'prev' | 'next') => {
    const newDate = new Date(currentDate);
    if (view === 'month') {
      newDate.setMonth(newDate.getMonth() + (dir === 'next' ? 1 : -1));
    } else {
      newDate.setDate(newDate.getDate() + (dir === 'next' ? 7 : -7));
    }
    setCurrentDate(newDate);
  };

  const today = new Date();
  const selectedEvents = getEventsForDate(selectedDate);

  // Todo List Data (Today + 3 days)
  const todoList = MOCK_EVENTS.filter(e => {
    const diff = normalizeDate(e.date).getTime() - normalizeDate(today).getTime();
    const dayDiff = diff / (1000 * 3600 * 24);
    return dayDiff >= 0 && dayDiff <= 3 && !e.completed;
  }).sort((a, b) => a.date.getTime() - b.date.getTime());

  return (
    <div className="bg-white rounded-xl shadow-[0_2px_10px_-2px_rgba(0,0,0,0.05)] border border-[#EAECEF] overflow-hidden flex flex-col h-full">
      {/* Header */}
      <div className="px-5 py-4 border-b border-gray-50 flex items-center justify-between bg-white">
        <div className="flex items-center gap-2">
           <div className="bg-brand/10 p-1.5 rounded-lg">
             <CalendarIcon size={16} className="text-brand" />
           </div>
           <span className="font-bold text-text-primary">投标日历</span>
        </div>
        <div className="flex gap-2">
           <div className="flex bg-gray-50 rounded-lg p-0.5">
            <button 
              onClick={() => setView('month')}
              className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                view === 'month' ? 'bg-white text-brand shadow-sm' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              月
            </button>
            <button 
              onClick={() => setView('week')}
              className={`px-3 py-1 text-xs font-medium rounded-md transition-all ${
                view === 'week' ? 'bg-white text-brand shadow-sm' : 'text-gray-500 hover:text-gray-700'
              }`}
            >
              周
            </button>
          </div>
        </div>
      </div>

      {/* Navigation Bar */}
      <div className="flex items-center justify-between px-4 py-2 mt-1">
        <button 
          onClick={() => navigate('prev')} 
          className="p-1.5 hover:bg-gray-50 rounded-full text-gray-400 hover:text-brand transition-colors"
        >
          <ChevronLeft size={16}/>
        </button>
        <span className="text-sm font-bold text-text-primary font-mono tracking-wide">
          {currentDate.getFullYear()}年{currentDate.getMonth() + 1}月
        </span>
        <button 
          onClick={() => navigate('next')} 
          className="p-1.5 hover:bg-gray-50 rounded-full text-gray-400 hover:text-brand transition-colors"
        >
          <ChevronRight size={16}/>
        </button>
      </div>

      {/* Calendar Grid */}
      <div className="px-3 pb-3">
        {/* Week Headers */}
        <div className="grid grid-cols-7 mb-2">
          {['一', '二', '三', '四', '五', '六', '日'].map(d => (
            <div key={d} className="text-center text-[10px] font-medium text-text-tertiary uppercase tracking-wider">{d}</div>
          ))}
        </div>

        {/* Days Grid - No borders, just gap */}
        <div className="grid grid-cols-7 gap-1.5">
          {getCalendarDays().map((item, idx) => (
            <CalendarDay 
              key={idx}
              date={item.date}
              isCurrentMonth={item.isCurrentMonth}
              isToday={normalizeDate(item.date).getTime() === normalizeDate(today).getTime()}
              isSelected={normalizeDate(item.date).getTime() === normalizeDate(selectedDate).getTime()}
              events={getEventsForDate(item.date)}
              onClick={handleDateClick}
              view={view}
            />
          ))}
        </div>
      </div>

      {/* Legend - Minimalist */}
      <div className="px-5 pb-3 flex gap-4 justify-center border-b border-gray-50">
        <div className="flex items-center gap-1.5">
          <div className="w-1.5 h-1.5 rounded-full bg-functional-error" />
          <span className="text-[10px] text-text-tertiary">截止</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-1.5 h-1.5 rounded-full bg-brand" />
          <span className="text-[10px] text-text-tertiary">开标</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-1.5 h-1.5 rounded-full bg-functional-warning" />
          <span className="text-[10px] text-text-tertiary">提醒</span>
        </div>
      </div>

      {/* Todo List Area */}
      <div className="flex-1 bg-gray-50/50 p-4 overflow-y-auto max-h-[280px]">
        <div className="flex items-center justify-between mb-3">
           <h4 className="text-xs font-bold text-text-secondary uppercase tracking-wider">近期待办</h4>
           <button 
             onClick={() => { setCurrentDate(new Date()); setSelectedDate(new Date()); }}
             className="text-[10px] text-brand hover:underline"
           >
             回到今天
           </button>
        </div>

        <div className="space-y-2.5">
          {todoList.length > 0 ? (
            todoList.map(event => (
              <div 
                key={event.id} 
                className="group bg-white p-3 rounded-lg border border-gray-100 shadow-sm hover:shadow-md hover:border-brand/20 transition-all cursor-pointer relative overflow-hidden"
              >
                <div className={`absolute left-0 top-0 bottom-0 w-1 ${
                  event.type === EventType.DEADLINE ? 'bg-functional-error' : 
                  event.type === EventType.OPENING ? 'bg-brand' : 'bg-functional-warning'
                }`} />
                <div className="pl-2.5">
                  <div className="flex justify-between items-center mb-1">
                    <span className="text-xs font-bold text-text-primary">
                      {event.date.getMonth()+1}月{event.date.getDate()}日 <span className="text-gray-400 font-normal ml-1">{event.timeStr}</span>
                    </span>
                  </div>
                  <p className="text-xs text-text-secondary truncate group-hover:text-brand transition-colors" title={event.projectName}>
                    {event.projectName}
                  </p>
                </div>
              </div>
            ))
          ) : (
             <div className="flex flex-col items-center justify-center py-6 text-gray-400">
               <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mb-2">
                 <CheckSquare size={14} className="opacity-50" />
               </div>
               <span className="text-xs">近期无待办事项</span>
             </div>
          )}
        </div>
      </div>

      {/* Modal Dialog (Simplified for brevity) */}
      {modalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-[2px] animate-in fade-in duration-200">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-sm mx-4 overflow-hidden animate-in zoom-in-95 duration-200 border border-gray-100">
            <div className="p-4 border-b border-gray-50 flex justify-between items-center bg-gray-50/50">
              <h3 className="font-bold text-text-primary text-sm">
                {selectedDate.getMonth()+1}月{selectedDate.getDate()}日 事项
              </h3>
              <button onClick={() => setModalOpen(false)} className="text-gray-400 hover:text-gray-600 p-1 hover:bg-gray-100 rounded">
                <X size={16} />
              </button>
            </div>
            <div className="p-4 max-h-[300px] overflow-y-auto space-y-3">
              {selectedEvents.map(event => (
                <div key={event.id} className="p-3 bg-white rounded-lg border border-gray-100 shadow-sm">
                  <div className="flex items-start gap-2.5">
                    <div className={`mt-1.5 w-2 h-2 rounded-full shrink-0 ${
                      event.type === EventType.DEADLINE ? 'bg-functional-error' : 
                      event.type === EventType.OPENING ? 'bg-brand' : 'bg-functional-warning'
                    }`} />
                    <div className="flex-1">
                      <h5 className="text-sm font-medium text-text-primary leading-snug mb-1">{event.projectName}</h5>
                      <p className="text-xs text-text-tertiary mb-2">截止时间: {event.timeStr}</p>
                      <button className="text-xs flex items-center justify-center w-full py-1.5 gap-1 text-brand bg-brand/5 hover:bg-brand/10 rounded font-medium transition-colors">
                        <CheckSquare size={12} /> 标记完成
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

