// Mock AI Data
const AI_EXTRACTED_DATA = {
  name: '江苏省南京市江北新区市政道路改造工程',
  region: '江苏',
  deadline: '2026-02-10T17:00',
  opening: '2026-02-11T09:00'
};

export const CreateProjectModal: React.FC<CreateProjectModalProps> = ({ isOpen, onClose, onCreate }) => {
  const [step, setStep] = useState<'form' | 'parsing'>('form');
  const [file, setFile] = useState<File | null>(null);
  const [isParsing, setIsParsing] = useState(false);
  const [parsingProgress, setParsingProgress] = useState(0);
  const [aiSuccess, setAiSuccess] = useState(false);

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    region: '',
    deadline: '',
    opening: ''
  });
  const [errors, setErrors] = useState<Record<string, string>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Reset state when opening
  useEffect(() => {
    if (isOpen) {
      setStep('form');
      setFile(null);
      setIsParsing(false);
      setAiSuccess(false);
      setFormData({ name: '', region: '', deadline: '', opening: '' });
      setErrors({});
    }
  }, [isOpen]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      if (selectedFile.size > 200 * 1024 * 1024) {
        alert("文件大小不能超过 200MB");
        return;
      }
      setFile(selectedFile);
      startParsing();
    }
  };

  const startParsing = () => {
    setStep('parsing');
    setIsParsing(true);
    setParsingProgress(0);

    // Simulate progress
    const interval = setInterval(() => {
      setParsingProgress(prev => {
        if (prev >= 90) {
          clearInterval(interval);
          return 90;
        }
        return prev + 10;
      });
    }, 150);

    // Simulate completion
    setTimeout(() => {
      clearInterval(interval);
      setParsingProgress(100);
      setIsParsing(false);

      // Auto-fill form
      setFormData({
        name: AI_EXTRACTED_DATA.name,
        region: AI_EXTRACTED_DATA.region,
        deadline: AI_EXTRACTED_DATA.deadline,
        opening: AI_EXTRACTED_DATA.opening
      });
      setAiSuccess(true);
      setStep('form');
    }, 2000);
  };

  const handleSubmit = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.name) newErrors.name = '请输入项目名称';
    if (!formData.region) newErrors.region = '请选择所属地区';

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    const newProject: Partial<Project> = {
      name: formData.name,
      region: formData.region,
      status: file ? ProjectStatus.IN_PROGRESS : ProjectStatus.CREATED,
      deadline: formData.deadline ? new Date(formData.deadline) : undefined,
      openingDate: formData.opening ? new Date(formData.opening) : undefined,
    };

    onCreate(newProject);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px]" onClick={onClose} />

      {/* Modal Content */}
      <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <h2 className="text-lg font-bold text-text-primary">创建项目</h2>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Body */}
        <div className="p-6 overflow-y-auto">

          {/* Parsing State */}
          {step === 'parsing' ? (
            <div className="flex flex-col items-center justify-center py-12 text-center">
              <div className="relative mb-6">
                <div className="w-16 h-16 border-4 border-blue-100 border-t-brand rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center font-bold text-xs text-brand">
                  {parsingProgress}%
                </div>
              </div>
              <h3 className="text-lg font-medium text-text-primary mb-2">正在解析招标文件...</h3>
              <p className="text-sm text-text-tertiary mb-6">AI正在提取项目名称、关键时间节点和评审规则</p>

              <div className="w-full max-w-xs space-y-2 text-xs text-text-secondary bg-gray-50 p-4 rounded-lg text-left">
                <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-brand"/> 解析文件结构...</div>
                {parsingProgress > 40 && <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-brand"/> 提取关键要素...</div>}
                {parsingProgress > 70 && <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-brand"/> 匹配规则库...</div>}
              </div>
            </div>
          ) : (
            /* Form State */
            <div className="space-y-5">

              {/* AI Success Banner */}
              {aiSuccess && (
                <div className="bg-green-50 border border-green-100 rounded-lg p-3 flex items-start gap-3 animate-in fade-in slide-in-from-top-2">
                   <CheckCircle size={18} className="text-functional-success mt-0.5 shrink-0" />
                   <div>
                     <p className="text-sm font-medium text-green-800">招标文件解析完成</p>
                     <p className="text-xs text-green-600 mt-0.5">AI已自动为您填充了项目信息，请核对是否准确。</p>
