import React, { useState } from 'react';
import { ProjectCard } from './ProjectCard';
import { Project, ProjectStatus } from '../../types';
import { Filter, Plus, Search, ClipboardList } from 'lucide-react';
import { Button } from '../UI/Button';

interface ProjectListProps {
  projects: Project[];
  onCreateClick: () => void;
  onProjectClick: (project: Project) => void;
}

export const ProjectList: React.FC<ProjectListProps> = ({ projects, onCreateClick, onProjectClick }) => {
  const [filterStatus, setFilterStatus] = useState<'ALL' | 'ACTIVE' | 'DONE' | 'ARCHIVED'>('ACTIVE');
  const [searchQuery, setSearchQuery] = useState('');

  // Filter Logic
  const filteredProjects = projects.filter(p => {
    // 1. Text Search
    if (searchQuery && !p.name.includes(searchQuery)) return false;

    // 2. Tab Filter
    if (filterStatus === 'ALL') return true;
    if (filterStatus === 'ACTIVE') {
      return [
        ProjectStatus.CREATED, 
        ProjectStatus.IN_PROGRESS, 
        ProjectStatus.CHECKING, 
        ProjectStatus.SUBMITTED,
        ProjectStatus.OPENED
      ].includes(p.status);
    }
    if (filterStatus === 'DONE') {
      return [ProjectStatus.WON, ProjectStatus.LOST].includes(p.status);
    }
    // Assume archived is empty for now or specific status
    if (filterStatus === 'ARCHIVED') return false; 

    return true;
  }).sort((a, b) => b.lastUpdated.getTime() - a.lastUpdated.getTime());

  const tabs = [
    { key: 'ACTIVE', label: '进行中' },
    { key: 'ALL', label: '全部' },
    { key: 'DONE', label: '已完成' },
    { key: 'ARCHIVED', label: '已归档' },
  ];

  return (
    <div className="flex flex-col h-full">
      {/* Header & Controls */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-6 gap-4">
        <div className="flex items-center gap-1 bg-white p-1 rounded-lg border border-[#D9DCDF]">
          {tabs.map(tab => (
            <button
              key={tab.key}
              onClick={() => setFilterStatus(tab.key as any)}
              className={`px-4 py-1.5 text-sm rounded-md transition-all ${
                filterStatus === tab.key 
                ? 'bg-brand/10 text-brand font-medium shadow-sm' 
                : 'text-text-secondary hover:text-text-primary hover:bg-gray-50'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-3">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder="搜索项目名称" 
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="pl-9 pr-4 py-1.5 h-9 text-sm border border-[#D9DCDF] rounded-md focus:border-brand focus:ring-1 focus:ring-brand outline-none w-48 transition-all"
            />
          </div>
          <button className="p-2 border border-[#D9DCDF] rounded-md text-gray-500 hover:text-brand hover:border-brand transition-colors bg-white">
            <Filter size={16} />
          </button>
        </div>
      </div>

      {/* List Content */}
      <div className="flex-1 space-y-4 min-h-[400px]">
        {filteredProjects.length > 0 ? (
          filteredProjects.map(project => (
            <ProjectCard 
              key={project.id} 
              project={project} 
              onClick={() => onProjectClick(project)} 
            />
          ))
        ) : (
          <div className="h-64 flex flex-col items-center justify-center bg-white rounded-lg border border-dashed border-gray-300">
            <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4">
              <ClipboardList size={32} className="text-gray-400" />
            </div>
            <h3 className="text-text-primary font-medium mb-1">还没有创建项目</h3>
            <p className="text-text-tertiary text-sm mb-4">创建项目开始您的标书检查之旅</p>
            <Button size="sm" onClick={onCreateClick}>
              <Plus size={16} className="mr-1" /> 创建项目
            </Button>
          </div>
        )}
      </div>

      {/* Pagination / Load More */}
      {filteredProjects.length > 0 && (
        <div className="mt-4 text-center">
           <span className="text-xs text-text-tertiary">显示 {filteredProjects.length} 个项目</span>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { Project, ProjectStatus } from '../../types';
import { Clock, Calendar, ChevronRight, AlertTriangle, CheckCircle, Circle } from 'lucide-react';

interface ProjectCardProps {
  project: Project;
  onClick?: () => void;
}

const StatusBadge: React.FC<{ status: ProjectStatus }> = ({ status }) => {
  const styles = {
    [ProjectStatus.CREATED]: 'bg-gray-100 text-gray-600',
    [ProjectStatus.IN_PROGRESS]: 'bg-blue-50 text-brand border border-blue-100',
    [ProjectStatus.CHECKING]: 'bg-orange-50 text-orange-600 border border-orange-100 animate-pulse',
    [ProjectStatus.SUBMITTED]: 'bg-green-50 text-green-600 border border-green-100',
    [ProjectStatus.OPENED]: 'bg-purple-50 text-purple-600',
    [ProjectStatus.WON]: 'bg-red-50 text-red-600 border border-red-100',
    [ProjectStatus.LOST]: 'bg-gray-100 text-gray-400',
  };

  return (
    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${styles[status] || 'bg-gray-100'}`}>
      {status}
    </span>
  );
};

const ProgressIndicator: React.FC<{ label: string; status: 'success' | 'warning' | 'pending' }> = ({ label, status }) => {
  const icons = {
    success: <CheckCircle size={14} className="text-functional-success" />,
    warning: <AlertTriangle size={14} className="text-functional-warning" />,
    pending: <Circle size={14} className="text-gray-300" />
  };

  return (
    <div className="flex items-center gap-1.5" title={`${label}: ${status}`}>
      {icons[status]}
      <span className="text-xs text-text-tertiary">{label}</span>
    </div>
  );
};

export const ProjectCard: React.FC<ProjectCardProps> = ({ project, onClick }) => {
  // Calculate relative time or format date
  const formatDate = (date?: Date) => {
    if (!date) return '未设置';
    const month = date.getMonth() + 1;
    const day = date.getDate();
    return `${month}月${day}日`;
  };

  const getKeyDateLabel = () => {
    if (project.openingDate && new Date() > (project.deadline || new Date(0))) {
      return { label: '开标时间', date: project.openingDate, icon: Calendar };
    }
    return { label: '投标截止', date: project.deadline, icon: Clock };
  };

  const keyDate = getKeyDateLabel();
  const isUrgent = keyDate.date && (keyDate.date.getTime() - new Date().getTime() < 3 * 24 * 60 * 60 * 1000) && project.status === ProjectStatus.IN_PROGRESS;

  return (
    <div 
      onClick={onClick}
      className="group bg-white rounded-lg p-5 border border-transparent shadow-sm hover:shadow-lg hover:border-blue-100 hover:-translate-y-0.5 transition-all duration-300 cursor-pointer relative overflow-hidden"
    >
      {isUrgent && (
        <div className="absolute top-0 left-0 w-1 h-full bg-functional-warning"></div>
      )}

      <div className="flex justify-between items-start mb-3">
        <div className="flex-1 pr-4">
          <div className="flex items-center gap-2 mb-1">
            <h4 className="font-semibold text-text-primary text-base line-clamp-1 group-hover:text-brand transition-colors">
              {project.name}
            </h4>
            <StatusBadge status={project.status} />
          </div>
          <p className="text-xs text-text-tertiary">
            更新于 {formatDate(project.lastUpdated)}
          </p>
        </div>
        <div className={`flex flex-col items-end shrink-0 ${isUrgent ? 'text-functional-warning' : 'text-text-secondary'}`}>
           <div className="flex items-center gap-1 text-xs font-medium bg-gray-50 px-2 py-1 rounded group-hover:bg-white transition-colors">
             <keyDate.icon size={12} />
             <span>{keyDate.label}: {formatDate(keyDate.date)}</span>
           </div>
        </div>
      </div>

      <div className="h-px bg-gray-100 my-3 group-hover:bg-gray-50"></div>

      <div className="flex items-center justify-between">
        <div className="flex gap-4">
          <ProgressIndicator label="资信" status={project.progress.credit} />
          <ProgressIndicator label="技术" status={project.progress.technical} />
          <ProgressIndicator label="经济" status={project.progress.economic} />
        </div>

        <button className="text-xs text-brand font-medium flex items-center opacity-0 group-hover:opacity-100 transition-opacity -translate-x-2 group-hover:translate-x-0 duration-300">
          查看详情 <ChevronRight size={12} />
        </button>
      </div>
    </div>
  );
};

