import React, { useState, useRef, useEffect } from 'react';
import { X, UploadCloud, FileText, AlertCircle, CheckCircle, Trash2, FileWarning, Lock } from 'lucide-react';
import { Button } from '../UI/Button';

interface AddVersionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onImport: (files: File[], remark: string) => void;
}

interface FileItem {
  file: File;
  status: 'valid' | 'error_size' | 'error_format' | 'error_encrypted';
  id: string;
}

const MAX_SIZE = 200 * 1024 * 1024; // 200MB
const ALLOWED_EXTENSIONS = ['.pdf', '.zf', '.doc', '.docx', '.xls', '.xlsx'];

export const AddVersionModal: React.FC<AddVersionModalProps> = ({ isOpen, onClose, onImport }) => {
  const [fileList, setFileList] = useState<FileItem[]>([]);
  const [remark, setRemark] = useState('');
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      setFileList([]);
      setRemark('');
      setIsDragging(false);
    }
  }, [isOpen]);

  const validateFile = (file: File): FileItem['status'] => {
    // 1. Check Size
    if (file.size > MAX_SIZE) return 'error_size';

    // 2. Check Extension
    const ext = '.' + file.name.split('.').pop()?.toLowerCase();
    if (!ALLOWED_EXTENSIONS.includes(ext)) return 'error_format';

    // 3. Simulate Encrypted Check (Mock logic: filename contains "加密" or "lock")
    if (file.name.includes('加密') || file.name.toLowerCase().includes('lock')) return 'error_encrypted';

    return 'valid';
  };

  const handleFiles = (files: FileList | null) => {
    if (!files) return;
    const newItems: FileItem[] = Array.from(files).map(file => ({
      file,
      status: validateFile(file),
      id: Math.random().toString(36).substring(7)
    }));
    setFileList(prev => [...prev, ...newItems]);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    handleFiles(e.dataTransfer.files);
  };

  const removeFile = (id: string) => {
    setFileList(prev => prev.filter(item => item.id !== id));
  };

  const handleImportClick = () => {
    const validFiles = fileList.filter(item => item.status === 'valid').map(item => item.file);
    onImport(validFiles, remark);
  };

  const validCount = fileList.filter(item => item.status === 'valid').length;
  const hasInvalid = fileList.some(item => item.status !== 'valid');

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px]" onClick={onClose} />

      <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
          <div>
            <h2 className="text-lg font-bold text-text-primary">上传投标文件</h2>
            <p className="text-xs text-text-tertiary mt-0.5">上传非加密的投标文件，一次可上传多份，系统将自动为每份文件生成一个版本。</p>
          </div>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
            <X size={20} />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 flex-1 overflow-y-auto">
          {/* Upload Area */}
          <div 
            className={`
              border-2 border-dashed rounded-lg p-8 flex flex-col items-center justify-center cursor-pointer transition-all mb-6
              ${isDragging ? 'border-brand bg-brand/5' : 'border-gray-300 hover:border-brand hover:bg-brand/5'}
            `}
            onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
            onDragLeave={() => setIsDragging(false)}
            onDrop={handleDrop}
            onClick={() => fileInputRef.current?.click()}
          >
             <div className="w-12 h-12 bg-blue-50 text-brand rounded-full flex items-center justify-center mb-3">
               <UploadCloud size={24} />
             </div>
             <p className="text-sm font-medium text-text-primary">点击或拖拽文件到此处</p>
             <p className="text-xs text-text-tertiary mt-1">支持 PDF, ZF, Word, Excel 格式，文件大小 ≤200MB</p>
             <input type="file" multiple ref={fileInputRef} className="hidden" onChange={(e) => handleFiles(e.target.files)} />
          </div>

          {/* File List */}
          {fileList.length > 0 && (
            <div className="space-y-3 mb-6">
              <h3 className="text-sm font-bold text-text-secondary">待导入列表 ({validCount}/{fileList.length})</h3>
              <div className="space-y-2">
                {fileList.map((item) => (
                  <div key={item.id} className={`flex items-center justify-between p-3 rounded-lg border ${item.status === 'valid' ? 'bg-gray-50 border-gray-100' : 'bg-red-50 border-red-100'}`}>
                    <div className="flex items-center gap-3 overflow-hidden">
                      {item.status === 'valid' ? (
                        <FileText size={18} className="text-brand shrink-0" />
                      ) : (
                         item.status === 'error_encrypted' ? <Lock size={18} className="text-red-500 shrink-0" /> : <FileWarning size={18} className="text-red-500 shrink-0" />
                      )}
                      <div className="min-w-0">
                        <div className="flex items-center gap-2">
                          <p className={`text-sm font-medium truncate ${item.status === 'valid' ? 'text-text-primary' : 'text-red-600'}`}>{item.file.name}</p>
                          {item.status === 'valid' && <CheckCircle size={14} className="text-functional-success" />}
                        </div>
                        <p className="text-xs text-text-tertiary">
                          {(item.file.size / 1024 / 1024).toFixed(2)} MB
                          {item.status !== 'valid' && (
                            <span className="text-red-500 ml-2">
                              {item.status === 'error_size' && '超出大小限制'}
                              {item.status === 'error_format' && '不支持的文件格式'}
                              {item.status === 'error_encrypted' && '检测到文件加密，无法导入'}
                            </span>
                          )}
                        </p>
                      </div>
                    </div>
                    <button onClick={() => removeFile(item.id)} className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-white rounded transition-colors">
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Global Remark */}
          <div>
            <label className="block text-sm font-medium text-text-secondary mb-1">
              批量备注 <span className="text-xs text-gray-400 font-normal">(可选，将应用于所有导入版本)</span>
            </label>
            <input 
              type="text" 
              value={remark}
              onChange={(e) => setRemark(e.target.value)}
              placeholder="例如：来自XX招标文件批量导入"
              className="w-full px-3 py-2 border border-[#D9DCDF] rounded-md outline-none focus:border-brand focus:ring-2 focus:ring-brand/20 transition-all text-sm"
            />
          </div>
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-gray-100 bg-gray-50 flex items-center justify-between">
          <div className="text-xs">
            {hasInvalid && <span className="text-red-500 flex items-center gap-1"><AlertCircle size={12}/> 部分文件无法导入，请检查</span>}
          </div>
          <div className="flex gap-3">
            <Button variant="secondary" onClick={onClose}>取消</Button>
            <Button 
              variant="primary" 
              onClick={handleImportClick} 
              disabled={validCount === 0}
              className={validCount === 0 ? "opacity-50 cursor-not-allowed" : ""}
            >
              导入版本 ({validCount})
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
