import { AddVersionModal } from '../Modals/AddVersionModal';

interface ProjectDetailProps {
  project: Project;
  onBack: () => void;
}

// Mock Helper for file size
const formatSize = (bytes: number) => {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

// Mock Helper for date format
const formatDate = (date?: Date) => {
  if (!date) return '未设置';
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')} ${String(date.getHours()).padStart(2, '0')}:${String(date.getMinutes()).padStart(2, '0')}`;
};

export const ProjectDetail: React.FC<ProjectDetailProps> = ({ project, onBack }) => {
  // Initialize versions state from props
  const [versions, setVersions] = useState<ProposalVersion[]>(project.versions || [
    {
      id: 'v1',
      name: '投标文件-1',
      remark: '第一次编写的版本',
      uploadTime: new Date('2026-02-03T14:20:00'),
      files: {
        credit: { id: 'fv1_1', name: '资信标.pdf', size: 5200000, uploadTime: new Date('2026-02-03T14:20:00') },
        technical: { id: 'fv1_2', name: '技术标.pdf', size: 8700000, uploadTime: new Date('2026-02-03T14:20:00') },
        economic: { id: 'fv1_3', name: '经济标.xlsx', size: 2100000, uploadTime: new Date('2026-02-03T14:20:00') },
      },
      checkStatus: {
        credit: { status: 'success', issueCount: 0 },
        technical: { status: 'warning', issueCount: 2 },
        economic: { status: 'pending', issueCount: 0 },
      }
