    setExpandedVersions(prev => 
      prev.includes(id) ? prev.filter(v => v !== id) : [...prev, id]
    );
  };

  const handleImportVersions = (files: File[], remark: string) => {
    const newVersions: ProposalVersion[] = files.map(file => {
      // 1. Generate Name (Filename without extension)
      let baseName = file.name.replace(/\.[^/.]+$/, "");
      let finalName = baseName;
      let counter = 1;

      // Simple collision detection (mock)
      while (versions.some(v => v.name === finalName)) {
        finalName = `${baseName}-${counter}`;
        counter++;
      }

      // 2. Determine File Type Heuristic
      const lowerName = file.name.toLowerCase();
      let fileType: 'credit' | 'technical' | 'economic' = 'technical'; // default
      if (lowerName.includes('资信')) fileType = 'credit';
      else if (lowerName.includes('经济') || lowerName.includes('报价')) fileType = 'economic';
      else if (lowerName.includes('技术')) fileType = 'technical';

      // 3. Create Version Object
      const newFileObj: ProjectFile = {
        id: `f_${Date.now()}_${Math.random()}`,
        name: file.name,
        size: file.size,
        uploadTime: new Date()
      };

      return {
        id: `v_${Date.now()}_${Math.random()}`,
        name: finalName,
        remark: remark,
        uploadTime: new Date(),
        files: {
          [fileType]: newFileObj
        },
        checkStatus: {
          credit: { status: 'pending', issueCount: 0 },
          technical: { status: 'pending', issueCount: 0 },
          economic: { status: 'pending', issueCount: 0 },
        }
      };
    });

    setVersions(prev => [...newVersions, ...prev]); // Add new versions to top
    setExpandedVersions(prev => [...newVersions.map(v => v.id), ...prev]); // Auto expand new ones
