  const getDaysRemaining = (deadline?: Date) => {
    if (!deadline) return null;
    const diff = deadline.getTime() - new Date().getTime();
    const days = Math.ceil(diff / (1000 * 3600 * 24));
    return days;
  };

  const daysRemaining = getDaysRemaining(project.deadline);
