            </div>
          </div>
          <div>
            <label className="text-xs text-text-tertiary mb-1 block">开标时间</label>
            <div className="text-sm font-medium text-text-primary flex items-center gap-1">
              <Calendar size={14} className="text-gray-400" />
              {formatDate(project.openingDate)}
            </div>
          </div>
          <div>
            <label className="text-xs text-text-tertiary mb-1 block">创建时间</label>
            <div className="text-sm text-text-secondary">2026-02-03 10:30</div>
          </div>
          <div>
            <label className="text-xs text-text-tertiary mb-1 block">最近更新</label>
            <div className="text-sm text-text-secondary">{formatDate(project.lastUpdated)}</div>
          </div>
        </div>

        <div className="mt-8 grid grid-cols-1 lg:grid-cols-2 gap-4">
          {/* Progress & Risk */}
          <div className="space-y-4">
            <div>
              <div className="flex justify-between text-xs mb-1.5">
                <span className="text-text-secondary">整体进度</span>
                <span className="font-bold text-brand">80%</span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-brand w-[80%] rounded-full" />
              </div>
            </div>
            <div className="bg-orange-50 border border-orange-100 rounded-md p-3 flex items-start gap-2">
              <AlertTriangle size={16} className="text-functional-warning mt-0.5 shrink-0" />
              <p className="text-xs text-orange-800 leading-relaxed">
                <span className="font-bold">风险提示：</span>技术标检查发现2个问题，建议尽快处理。
              </p>
            </div>
          </div>

          {/* Action Guide */}
          <div className="bg-blue-50 border border-blue-100 rounded-md p-4 flex flex-col justify-between">
            <div className="flex items-start gap-2 mb-3">
              <Lightbulb size={16} className="text-brand mt-0.5 shrink-0" />
              <div>
                <p className="text-sm font-bold text-brand-dark mb-1">下一步建议</p>
                <p className="text-xs text-blue-700">处理技术标问题后重新检查，确保所有指标符合招标文件要求。</p>
              </div>
