            <div className="flex gap-2 justify-end">
              <Button size="sm" variant="secondary" className="h-7 text-xs bg-white">查看详情</Button>
              <Button size="sm" className="h-7 text-xs">开始修复</Button>
            </div>
          </div>
        </div>
      </div>

      {/* 2. File Management */}
      <div className="bg-white rounded-lg border border-[#D9DCDF] shadow-sm p-6">
        <h2 className="text-lg font-bold text-text-primary mb-6">文件管理</h2>

        {/* Tender Document */}
