             <Button 
               size="sm" 
               variant="outline" 
               className="h-8 gap-1"
               onClick={() => setIsAddVersionModalOpen(true)}
             >
               <Plus size={14} /> 添加版本
             </Button>
          </div>

          <div className="space-y-3">
            {versions.length === 0 && (
              <div className="text-center py-8 bg-gray-50 rounded-lg border border-dashed border-gray-200">
                <p className="text-sm text-text-tertiary">暂无投标文件版本</p>
                <p className="text-xs text-gray-400 mt-1">可以添加多个版本用于对比分析或保存历史记录</p>
              </div>
            )}

            {versions.map((version) => {
              const isExpanded = expandedVersions.includes(version.id);

              // Helper to count issues
              const issueCount = version.checkStatus.credit.issueCount + version.checkStatus.technical.issueCount + version.checkStatus.economic.issueCount;
