                      <div className="flex items-center gap-2 text-xs">
                         {isChecking ? (
                           <span className="flex items-center gap-1 text-brand"><Loader2 size={12} className="animate-spin"/> 检查中</span>
                         ) : hasIssues ? (
                           <span className="flex items-center gap-1 text-functional-warning"><AlertCircle size={12}/> 有问题 {issueCount}</span>
                         ) : isAllChecked ? (
                           <span className="flex items-center gap-1 text-functional-success"><CheckCircle size={12}/> 通过</span>
                         ) : (
                           <span className="flex items-center gap-1 text-gray-400"><div className="w-2 h-2 rounded-full border border-gray-400"/> 未检查</span>
                         )}
                      </div>

                      <div className="flex items-center gap-2">
                        <div className="h-4 w-px bg-gray-300"></div>
                        <button className="p-1 hover:bg-gray-200 rounded text-gray-500"><MoreHorizontal size={16}/></button>
                        <button className="p-1 hover:bg-gray-200 rounded text-gray-500">
                          {isExpanded ? <ChevronUp size={16}/> : <ChevronDown size={16}/>}
