                  {/* Body */}
                  {isExpanded && (
                    <div className="p-4 bg-white animate-in slide-in-from-top-2 duration-200">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                        {['credit', 'technical', 'economic'].map((type) => {
                          const file = version.files[type as keyof typeof version.files];
                          const status = version.checkStatus[type as keyof typeof version.checkStatus];
                          const typeLabel = type === 'credit' ? '资信标' : type === 'technical' ? '技术标' : '经济标';

                          return (
                            <div key={type} className="border border-gray-100 rounded-lg p-3 bg-gray-50/30 flex flex-col justify-between h-24">
                              <div className="flex justify-between items-start">
                                <div className="flex items-center gap-2">
                                  <File size={14} className="text-text-tertiary"/>
                                  <span className="text-xs font-bold text-text-secondary">{typeLabel}</span>
                                </div>
                                {/* Status Indicator */}
                                {status.status === 'success' && <CheckCircle size={14} className="text-functional-success"/>}
                                {status.status === 'warning' && <AlertCircle size={14} className="text-functional-warning"/>}
                                {status.status === 'pending' && <div className="w-3 h-3 rounded-full border border-gray-300"/>}
