                          )
                        })}
                      </div>

                      <div className="flex items-center justify-end gap-3 pt-3 border-t border-gray-50">
                        <Button variant="secondary" size="sm" className="h-8">查看检查结果</Button>
                        <Button variant="primary" size="sm" className="h-8">开始检查</Button>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* 3. Check Results (Summary) */}
      <div className="bg-white rounded-lg border border-[#D9DCDF] shadow-sm p-6">
         <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-bold text-text-primary">检查结果概览</h2>
            <span className="text-xs text-text-tertiary">基于最新版本: 投标文件-1</span>
         </div>
         <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
             {/* Credit */}
             <div className="p-4 bg-green-50 rounded-lg border border-green-100">
                <div className="flex items-center gap-2 mb-2">
                   <CheckCircle className="text-green-600" size={18} />
                   <h3 className="font-bold text-green-800">资信标</h3>
                </div>
                <p className="text-xs text-green-700">各项资质符合招标文件要求。</p>
             </div>
             {/* Technical */}
             <div className="p-4 bg-orange-50 rounded-lg border border-orange-100">
