             <p className="text-xs text-text-tertiary mt-1">支持 PDF, ZF, Word, Excel 格式，文件大小 ≤200MB</p>
             <input type="file" multiple ref={fileInputRef} className="hidden" onChange={(e) => handleFiles(e.target.files)} />
          </div>

          {/* File Table */}
          {fileList.length > 0 && (
            <div className="border border-gray-200 rounded-lg overflow-hidden">
              <table className="w-full text-sm text-left">
                <thead className="text-xs text-text-tertiary uppercase bg-gray-50 border-b border-gray-100">
                  <tr>
                    <th className="px-4 py-3 font-medium w-1/2">文件信息</th>
                    <th className="px-4 py-3 font-medium w-1/3">版本备注</th>
