                <tbody className="divide-y divide-gray-100">
                  {fileList.map((item) => (
                    <tr key={item.id} className="bg-white hover:bg-gray-50/50">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                           {item.status === 'valid' ? (
                            <FileText size={18} className="text-brand shrink-0" />
                          ) : (
                             item.status === 'error_encrypted' ? <Lock size={18} className="text-red-500 shrink-0" /> : <FileWarning size={18} className="text-red-500 shrink-0" />
                          )}
                          <div className="min-w-0 max-w-[300px]">
                            <div className="flex items-center gap-2">
                              <p className={`font-medium truncate ${item.status === 'valid' ? 'text-text-primary' : 'text-red-600'}`}>{item.file.name}</p>
                            </div>
                            <div className="flex items-center gap-2 mt-0.5">
                              <span className="text-xs text-text-tertiary">{(item.file.size / 1024 / 1024).toFixed(2)} MB</span>
                              {item.status === 'valid' ? (
                                <span className="text-[10px] bg-green-50 text-green-600 px-1.5 py-0.5 rounded border border-green-100">可导入</span>
                              ) : (
                                <span className="text-[10px] bg-red-50 text-red-600 px-1.5 py-0.5 rounded border border-red-100">
                                  {item.status === 'error_size' && '超出大小'}
                                  {item.status === 'error_format' && '格式错误'}
                                  {item.status === 'error_encrypted' && '文件加密'}
                                </span>
                              )}
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        <input 
                          type="text" 
                          value={item.remark}
                          onChange={(e) => updateRemark(item.id, e.target.value)}
                          disabled={item.status !== 'valid'}
                          placeholder={item.status === 'valid' ? "输入备注（可选）" : "无法导入"}
                          className="w-full px-3 py-1.5 text-sm border border-[#D9DCDF] rounded outline-none focus:border-brand focus:ring-1 focus:ring-brand/20 disabled:bg-gray-50 disabled:text-gray-400 transition-all placeholder:text-gray-300"
                        />
                      </td>
                      <td className="px-4 py-3 text-center">
                        <button 
                          onClick={() => removeFile(item.id)} 
                          className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-white rounded transition-colors inline-flex"
                        >
                          <Trash2 size={16} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-4 border-t border-gray-100 bg-gray-50 flex items-center justify-between">
          <div className="text-xs">
            {hasInvalid && <span className="text-red-500 flex items-center gap-1"><AlertCircle size={12}/> 部分文件存在问题，将自动忽略</span>}
             <span className="text-text-tertiary ml-2">已选 {fileList.length} 个文件，有效 {validCount} 个</span>
          </div>
          <div className="flex gap-3">
            <Button variant="secondary" onClick={onClose}>取消</Button>
            <Button 
              variant="primary" 
              onClick={handleImportClick} 
              disabled={validCount === 0}
              className={validCount === 0 ? "opacity-50 cursor-not-allowed" : ""}
            >
              导入版本 ({validCount})
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

