              )}
            </div>
          </div>
          <div>
            <label className="text-xs text-text-tertiary mb-1 block">开标时间</label>
            <div className="text-sm font-medium text-text-primary flex items-center gap-1">
              <Calendar size={14} className="text-gray-400" />
              {formatDate(project.openingDate)}
            </div>
          </div>
          <div>
            <label className="text-xs text-text-tertiary mb-1 block">创建时间</label>
            <div className="text-sm text-text-secondary">2026-02-03 10:30</div>
          </div>
          <div>
