        technical: { id: 'fv1_2', name: '技术标.pdf', size: 8700000, uploadTime: new Date('2026-02-03T14:20:00') },
        economic: { id: 'fv1_3', name: '经济标.xlsx', size: 2100000, uploadTime: new Date('2026-02-03T14:20:00') },
      },
      checkStatus: {
        credit: { status: 'success', issueCount: 0 },
