      // 1. Generate Name (Filename without extension)
      let baseName = file.name.replace(/\.[^/.]+$/, "");
      let finalName = baseName;
      let counter = 1;

      // Simple collision detection (mock)
      while (versions.some(v => v.name === finalName)) {
        finalName = `${baseName}-${counter}`;
        counter++;
      }

      // 2. Determine File Type Heuristic
      const lowerName = file.name.toLowerCase();
      let fileType: 'credit' | 'technical' | 'economic' = 'technical'; // default
      if (lowerName.includes('资信')) fileType = 'credit';
      else if (lowerName.includes('经济') || lowerName.includes('报价')) fileType = 'economic';
      else if (lowerName.includes('技术')) fileType = 'technical';

